import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.il0noOp3.js";const m=JSON.parse('{"title":"Credits & Attribution","description":"Credits and attribution for the AzureScout project.","frontmatter":{"description":"Credits and attribution for the AzureScout project."},"headers":[],"relativePath":"credits.md","filePath":"credits.md"}'),i={name:"credits.md"};function n(s,e,d,l,h,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="credits-attribution" tabindex="-1">Credits &amp; Attribution <a class="header-anchor" href="#credits-attribution" aria-label="Permalink to &quot;Credits &amp; Attribution&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>AzureScout exists because of <a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">Azure Resource Inventory (ARI)</a>.</strong> Without the foundation built by the ARI team at Microsoft, this project would not exist.</p></div><p>The full credits file is maintained in the repository root and rendered on GitHub.</p><p><a href="https://github.com/thisismydemo/azure-scout/blob/main/CREDITS.md" target="_blank" rel="noreferrer">View CREDITS.md on GitHub</a></p><h2 id="fork-origin" tabindex="-1">Fork Origin <a class="header-anchor" href="#fork-origin" aria-label="Permalink to &quot;Fork Origin&quot;">​</a></h2><p>AzureScout was forked from <a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">microsoft/ARI</a> (Azure Resource Inventory) at version <strong>3.6.11</strong> in October 2024. The original project provided the entire extraction, processing, and reporting pipeline — including its ARM inventory module set, the draw.io diagram engine, Excel/ImportExcel integration, and Azure Automation Account support. AzureScout has since added new ARM modules and an Entra ID module set that ARI does not have; the module is now at <strong>154 ARM + 17 Entra ID = 171 inventory modules</strong> — see <a href="./arm-modules.html">ARM Modules</a>, <a href="./entra-modules.html">Entra ID Modules</a>, and <a href="./ari-differences.html">Differences from ARI</a> for exactly what changed.</p><h2 id="original-authors" tabindex="-1">Original Authors <a class="header-anchor" href="#original-authors" aria-label="Permalink to &quot;Original Authors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Author</th><th>Role</th></tr></thead><tbody><tr><td><a href="https://github.com/Claudio-Merola" target="_blank" rel="noreferrer"><strong>Claudio Merola</strong></a></td><td>Original ARI creator and primary developer</td></tr><tr><td><a href="https://github.com/RenatoGregio" target="_blank" rel="noreferrer"><strong>Renato Gregio</strong></a></td><td>Original ARI co-author and copyright holder</td></tr></tbody></table><p>We are deeply grateful for their work. The ARI project remains actively maintained at <a href="https://github.com/microsoft/ARI" target="_blank" rel="noreferrer">github.com/microsoft/ARI</a> and we encourage users to check it out.</p><h2 id="what-has-changed" tabindex="-1">What Has Changed <a class="header-anchor" href="#what-has-changed" aria-label="Permalink to &quot;What Has Changed&quot;">​</a></h2><p>For a detailed breakdown of what AzureScout has added, changed, and diverged from the original ARI codebase, see <a href="./ari-differences.html">Differences from ARI</a>.</p><h2 id="additional-acknowledgments" tabindex="-1">Additional Acknowledgments <a class="header-anchor" href="#additional-acknowledgments" aria-label="Permalink to &quot;Additional Acknowledgments&quot;">​</a></h2><ul><li><strong><a href="https://github.com/dfinke" target="_blank" rel="noreferrer">Doug Finke</a></strong> — Author of <a href="https://github.com/dfinke/ImportExcel" target="_blank" rel="noreferrer">ImportExcel</a>, the PowerShell module used for Excel report generation (MIT license).</li><li><strong>Microsoft</strong> — Azure PowerShell SDK (<code>Az.*</code> modules), Azure Resource Graph, and Microsoft Graph REST API.</li><li><strong>All ARI contributors</strong> — The <a href="https://github.com/microsoft/ARI/graphs/contributors" target="_blank" rel="noreferrer">29 contributors</a> who built and refined ARI over six years.</li></ul><h2 id="license-disclaimer" tabindex="-1">License &amp; Disclaimer <a class="header-anchor" href="#license-disclaimer" aria-label="Permalink to &quot;License &amp; Disclaimer&quot;">​</a></h2><p>Both the original ARI project and AzureScout are licensed under the MIT License. See <a href="https://github.com/thisismydemo/azure-scout/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a> for full details.</p><p>AzureScout is an independent community project and is <strong>not affiliated with or endorsed by Microsoft</strong>.</p>',16)])])}const f=t(i,[["render",n]]);export{m as __pageData,f as default};
